import React, { useState, useContext } from 'react';
import axios from 'axios';
import { AuthContext } from '../contexts/AuthContext';

const API_URL = 'http://localhost:3001/api';

export default function AuthForm({ mode = 'login' }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useContext(AuthContext);

  const submit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const route = mode === 'login' ? '/auth/login' : '/auth/signup';
      const { data } = await axios.post(`${API_URL}${route}`, { username, password });
      login(data.token, data.user);
      window.location.href = '/';
    } catch (err) {
      setError(err.response?.data?.message || 'Authentication failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center px-4 py-12">  
      <div className="w-full max-w-xl">
        <div className="mb-8 text-center">
          <h1 className="text-4xl font-extrabold tracking-tight">Chess Arena</h1>
          <p className="mt-2 text-slate-400">{mode === 'login' ? 'Login and compete in real-time tournaments' : 'Create an account and start playing'}</p>
        </div>

        <div className="card p-8 bg-gradient-to-br from-slate-900/90 to-slate-800/90 border border-slate-700">
          <h2 className="text-2xl font-bold mb-6">{mode === 'login' ? 'Sign in' : 'Sign up'}</h2>

          <form onSubmit={submit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-300 mb-2">Username</label>
              <input 
                value={username} 
                onChange={(e) => setUsername(e.target.value)} 
                placeholder="username"
                className="input-field" 
                required 
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-300 mb-2">Password</label>
              <input 
                type="password" 
                value={password} 
                onChange={(e) => setPassword(e.target.value)} 
                placeholder="password"
                className="input-field" 
                required 
              />
            </div>

            {error && (
              <div className="p-3 rounded-lg bg-red-800/40 border border-red-500">
                <p className="error">{error}</p>
              </div>
            )}

            <button 
              type="submit"
              disabled={loading}
              className="btn-primary w-full disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {loading ? 'Loading...' : (mode === 'login' ? 'Sign In' : 'Create Account')}
            </button>
          </form>

          <div className="mt-6 text-sm text-center text-slate-400">
            {mode === 'login' ? (
              <>New to Chess Arena? <a href="/signup" className="text-cyan-300 font-semibold">Create account</a></>
            ) : (
              <>Already have an account? <a href="/login" className="text-cyan-300 font-semibold">Sign in</a></>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
